                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3">
                  {Object.entries(FRAMEWORKS).map(([key, framework]) => (
                    <button
                      key={key}
                      onClick={() => setSelectedFramework(key)}
                      className={`p-4 rounded-lg border-2 transition-all duration-200 text-left focus:outline-none focus:ring-2 focus:ring-offset-2 dark:focus:ring-offset-slate-800 focus:ring-blue-500 ${
                        selectedFramework === key
                          ? `${framework.color} text-white border-transparent shadow-md`
                          : 'bg-white text-gray-700 border-gray-200 hover:border-gray-400 hover:bg-gray-50 dark:bg-slate-700 dark:text-gray-200 dark:border-slate-600 dark:hover:border-slate-400 dark:hover:bg-slate-600 hc-bg hc-border hc-text'
                      }`}
                    >
                      <div className="font-semibold text-sm">{framework.name}</div>
                      <div className="text-xs mt-1 opacity-90">{framework.phases.length} phases</div>
                    </button>
                  ))}
                </div>
              </section>

              {/* Progress Bar */}
              <section className="bg-white dark:bg-slate-800 rounded-xl shadow-lg p-6 mb-6 hc-bg hc-border">
                <div className="flex justify-between items-center mb-3">
                  <h2 className="text-lg font-semibold text-gray-800 dark:text-gray-100 hc-text-yellow">Overall Progress</h2>
                  <button
                    onClick={resetProgress}
                    className="text-sm text-red-600 hover:text-red-800 dark:text-red-500 dark:hover:text-red-400 font-medium transition-colors"
                  >
                    Reset Progress
                  </button>
                </div>
                <div className="w-full bg-gray-200 dark:bg-slate-700 rounded-full h-4 mb-2 overflow-hidden hc-bg hc-border">
                  <div
                    className={`h-4 rounded-full ${currentFramework.color} transition-all duration-500 ease-out`}
                    style={{ width: `${progress}%` }}
                  ></div>
                </div>
                <p className="text-sm text-gray-600 dark:text-gray-400 hc-text">{progress}% Complete ({currentFramework.phases.filter(p => phaseStatuses[p.id] === 'complete').length}/{currentFramework.phases.length} phases)</p>
              </section>

              {/* Phase List */}
              <main className="space-y-4">
                {currentFramework.phases.map((phase) => (
