                            {copiedPhase === phase.id ? (
                              <>
                                <Check className="w-4 h-4" />
                                <span>Copied!</span>
                              </>
                            ) : (
                              <>
                                <Copy className="w-4 h-4" />
                                <span>Copy Directive</span>
                              </>
                            )}
                          </button>
                        </div>
                        <pre className="bg-slate-800 text-slate-200 p-4 rounded-lg border border-gray-200 text-sm overflow-x-auto whitespace-pre-wrap font-mono selection:bg-blue-400 selection:text-white dark:bg-black/50 dark:border-slate-700 dark:text-slate-300 hc-bg-code hc-text-code hc-border">
                          {phase.directive}
                        </pre>
                      </div>
                    )}
                  </div>
