              </main>

              {/* Footer Info */}
              <footer className="mt-8 bg-blue-50 border border-blue-200 rounded-xl p-6 dark:bg-blue-950 dark:border-blue-800 hc-bg-info">
                <h3 className="font-semibold text-blue-900 dark:text-blue-200 mb-2 hc-text-info">Usage Instructions</h3>
                <ul className="text-sm text-blue-800 dark:text-blue-300 list-disc list-inside space-y-1 hc-text">
