                <p className="text-sm text-gray-600 dark:text-gray-400 hc-text">{progress}% Complete ({currentFramework.phases.filter(p => phaseStatuses[p.id] === 'complete').length}/{currentFramework.phases.length} phases)</p>
              </section>

              {/* Phase List */}
              <main className="space-y-4">
                {currentFramework.phases.map((phase) => (
                  <div key={phase.id} className="bg-white dark:bg-slate-800 rounded-xl shadow-lg overflow-hidden transition-shadow hover:shadow-xl dark:hover:shadow-blue-900/50 hc-bg hc-border">
                    {/* Phase Header */}
                    <div className="p-6">
                      <div className="flex items-start justify-between">
                        <div className="flex items-start space-x-4 flex-1 min-w-0">
                          <div className="mt-1 flex-shrink-0">
                            {getStatusIcon(phase.id)}
                          </div>
                          <div className="flex-1 min-w-0">
                            <h3 className="text-lg font-semibold text-gray-800 dark:text-gray-100 mb-2 truncate hc-text-yellow">{phase.name}</h3>
                            <div className="flex items-center gap-2 mb-3">
                                <div className="flex flex-wrap gap-2">
                                    {phase.items.map((item, i) => (
                                    <span key={i} className="text-xs bg-gray-100 text-gray-700 px-3 py-1 rounded-full dark:bg-slate-700 dark:text-gray-300 hc-bg hc-border hc-text">
                                        {item}
                                    </span>
                                    ))}
                                </div>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        copyItemsToClipboard(phase.items, phase.id);
                                    }}
                                    className="p-1.5 rounded-md hover:bg-gray-100 dark:hover:bg-slate-700 text-gray-400 hover:text-blue-500 transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500"
                                    title="Copy items list"
                                    aria-label="Copy items list"
                                >
                                    {copiedItemsPhase === phase.id ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                                </button>
                            </div>
                          </div>
                        </div>

                        <div className="flex items-center space-x-2 ml-4 flex-shrink-0">
                          {phase.directive && (
                            <button
                              onClick={() => setExpandedPhase(expandedPhase === phase.id ? null : phase.id)}
                              className="p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 hc-hover-bg-gray"
                              aria-expanded={expandedPhase === phase.id}
                              aria-controls={`directive-${phase.id}`}
                              aria-label={expandedPhase === phase.id ? "Collapse directive" : "Expand directive"}
                            >
                              {expandedPhase === phase.id ? (
                                <ChevronDown className="w-5 h-5 text-gray-600 dark:text-gray-400 hc-text" />
                              ) : (
                                <ChevronRight className="w-5 h-5 text-gray-600 dark:text-gray-400 hc-text" />
                              )}
                            </button>
                          )}
                        </div>
                      </div>

                      {/* Status Buttons */}
                      <div className="flex flex-wrap gap-2 mt-4">
                        <button onClick={() => updatePhaseStatus(phase.id, 'in-progress')} className={`hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium transition-colors ${phaseStatuses[phase.id] === 'in-progress' ? 'bg-yellow-500 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-slate-700 dark:text-gray-300 dark:hover:bg-slate-600'}`}>In Progress</button>
                        <button onClick={() => updatePhaseStatus(phase.id, 'complete')} className={`hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium transition-colors ${phaseStatuses[phase.id] === 'complete' ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-slate-700 dark:text-gray-300 dark:hover:bg-slate-600'}`}>Complete</button>
                        <button onClick={() => updatePhaseStatus(phase.id, 'blocked')} className={`hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium transition-colors ${phaseStatuses[phase.id] === 'blocked' ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-slate-700 dark:text-gray-300 dark:hover:bg-slate-600'}`}>Blocked</button>
                        {phaseStatuses[phase.id] && (
                          <button onClick={() => updatePhaseStatus(phase.id, null)} className="hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-slate-700 dark:text-gray-300 dark:hover:bg-slate-600">Clear</button>
                        )}
                      </div>
                    </div>

                    {/* Expandable Directive */}
                    {phase.directive && expandedPhase === phase.id && (
                      <div id={`directive-${phase.id}`} className="border-t border-gray-200 bg-gray-50 p-6 dark:border-slate-700 dark:bg-slate-900/50 hc-bg hc-border">
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-3 gap-3">
                          <h4 className="font-semibold text-gray-800 dark:text-gray-200 hc-text-yellow">Copy & Paste Directive</h4>
                          <button
                            onClick={() => copyToClipboard(phase.directive || '', phase.id)}
                            className="flex items-center space-x-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors w-full sm:w-auto justify-center"
                          >
                            {copiedPhase === phase.id ? (
                              <>
                                <Check className="w-4 h-4" />
                                <span>Copied!</span>
                              </>
                            ) : (
                              <>
                                <Copy className="w-4 h-4" />
