                          <h4 className="font-semibold text-[#2D241E] dark:text-[#EAE0D5] hc-text-yellow">Copy & Paste Directive</h4>
                          <button
                            onClick={() => copyToClipboard(phase.directive || '', phase.id)}
                            className="flex items-center space-x-2 px-4 py-2 bg-[#C5A059] text-white rounded-lg hover:bg-[#B08D4C] transition-colors w-full sm:w-auto justify-center"
                          >
                            {copiedPhase === phase.id ? (
                              <>
                                <Check className="w-4 h-4" />
                                <span>Copied!</span>
                              </>
                            ) : (
                              <>
                                <Copy className="w-4 h-4" />
                                <span>Copy Directive</span>
