                  <li>Switch between frameworks to manage different compliance implementations.</li>
                </ul>
                <div className="mt-4 pt-4 border-t border-[#C5A059]/30 text-xs text-center text-[#2D241E] dark:text-[#EAE0D5] opacity-75">
                  System Version 3.0 • Project Refresh Baseline
                </div>
              </footer>
            </>
          ) : (
            <PuppeteerSelfTest />
          )}

        </div>
      </div>
      <AdminPanel isOpen={isAdminPanelOpen} onClose={() => setIsAdminPanelOpen(false)} />
    </>
  );
};

export default ComplianceWorkflowDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { useLocalStorage, useSimpleHash } from '../hooks';
import { AuditLogEntry } from '../types';
import { ShieldCheck, Lock } from './icons';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ isOpen, onClose }) => {
  const [passwordHash, setPasswordHash] = useLocalStorage<string | null>('admin-password-hash', null);
  const [auditLog, setAuditLog] = useLocalStorage<AuditLogEntry[]>('admin-audit-log', []);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const hash = useSimpleHash();

  const passwordInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen && !isAuthenticated) {
      setTimeout(() => passwordInputRef.current?.focus(), 100);
    }
  }, [isOpen, isAuthenticated]);

  const addLog = (action: string) => {
    const newLogEntry: AuditLogEntry = {
      timestamp: new Date().toISOString(),
      action,
    };
    // Prepend to keep the log sorted by most recent
    setAuditLog(currentLog => [newLogEntry, ...currentLog]);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!passwordHash) { // First time setup
      if (passwordInput.length < 8) {
        setError('Password must be at least 8 characters long.');
        return;
      }
      const newHash = await hash(passwordInput);
      setPasswordHash(newHash);
      addLog('Admin password set.');
      setIsAuthenticated(true);
      setError('');
      setPasswordInput('');
    } else { // Login
      const inputHash = await hash(passwordInput);
      if (inputHash === passwordHash) {
        addLog('Admin logged in.');
        setIsAuthenticated(true);
        setError('');
        setPasswordInput('');
      } else {
        addLog('Failed login attempt.');
        setError('Incorrect password.');
      }
    }
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (newPassword.length < 8) {
      setError('New password must be at least 8 characters long.');
      return;
    }
    if (newPassword !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }
    const newHash = await hash(newPassword);
    setPasswordHash(newHash);
    addLog('Admin password changed.');
    setNewPassword('');
    setConfirmPassword('');
    alert('Password changed successfully.');
  };

  const handleLogout = () => {
    addLog('Admin logged out.');
    setIsAuthenticated(false);
    onClose();
  };

  const clearLogs = () => {
    if (window.confirm('Are you sure you want to clear all audit logs?')) {
        addLog('Audit logs cleared.');
        setAuditLog([auditLog[0]]); // Keep the "cleared" log entry
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4" aria-modal="true" role="dialog" aria-labelledby="admin-panel-title">
      <div className={`hc-bg hc-border bg-white dark:bg-[#2D241E] rounded-lg shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto p-6 sm:p-8`}>
        <div className="flex justify-between items-center mb-4">
            <h2 id="admin-panel-title" className="text-2xl font-bold text-[#2D241E] dark:text-[#C5A059] hc-text-yellow">Admin Section</h2>
            <button onClick={onClose} className="p-1 rounded-full text-gray-500 hover:text-gray-800 dark:text-gray-400 dark:hover:text-white hc-text text-2xl leading-none" aria-label="Close admin panel">&times;</button>
        </div>

        {!isAuthenticated ? (
          <form onSubmit={handleLogin}>
            <h3 className="text-lg font-semibold mb-2 text-[#3E3228] dark:text-[#EAE0D5] hc-text">
                {passwordHash ? 'Admin Login' : 'Create Admin Password'}
            </h3>
            <p className="text-sm text-gray-600 dark:text-gray-400 mb-4 hc-text">
                {passwordHash ? 'Enter the password to access the admin section.' : 'Create a password to secure the admin section. Minimum 8 characters.'}
            </p>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
              <input
                ref={passwordInputRef}
                type="password"
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                placeholder="Enter password"
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-[#C5A059] focus:border-[#C5A059] dark:bg-[#1F1A17] dark:border-slate-600 dark:text-white"
                aria-label="Admin password"
              />
            </div>
            {error && <p className="text-red-500 text-sm mt-2">{error}</p>}
            <button type="submit" className="mt-4 w-full bg-[#C5A059] text-white font-semibold py-2 px-4 rounded-md hover:bg-[#B08D4C] transition-colors">
              {passwordHash ? 'Login' : 'Set Password'}
            </button>
          </form>
        ) : (
          <div className="space-y-8">
            <div className="flex justify-between items-center">
                <div className="flex items-center space-x-2">
                    <ShieldCheck className="w-6 h-6 text-green-500" />
                    <span className="font-semibold text-green-600 dark:text-green-400">Authenticated</span>
                </div>
                <button onClick={handleLogout} className="text-sm text-red-600 hover:text-red-800 dark:text-red-400 font-medium transition-colors">Logout</button>
            </div>

            <div className="p-4 border border-gray-200 dark:border-slate-700 rounded-lg">
                <h3 className="text-lg font-semibold mb-2 text-[#3E3228] dark:text-[#EAE0D5] hc-text">Change Password</h3>
                <form onSubmit={handleChangePassword} className="space-y-3">
                    <input type="password" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="New Password" className="w-full p-2 border rounded-md dark:bg-[#1F1A17] dark:border-slate-600 dark:text-white focus:border-[#C5A059] focus:ring-[#C5A059]" aria-label="New admin password"/>
                    <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm New Password" className="w-full p-2 border rounded-md dark:bg-[#1F1A17] dark:border-slate-600 dark:text-white focus:border-[#C5A059] focus:ring-[#C5A059]" aria-label="Confirm new admin password"/>
                    {error && <p className="text-red-500 text-sm">{error}</p>}
                    <button type="submit" className="bg-[#C5A059] text-white font-semibold py-2 px-4 rounded-md hover:bg-[#B08D4C] transition-colors">Update Password</button>
                </form>
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <h3 className="text-lg font-semibold text-[#3E3228] dark:text-[#EAE0D5] hc-text">Audit Log</h3>
                <button onClick={clearLogs} className="text-sm text-red-600 hover:text-red-800 dark:text-red-400 font-medium transition-colors">Clear Logs</button>
              </div>
              <div role="log" className="bg-[#F9F7F2] dark:bg-[#1F1A17] border border-gray-200 dark:border-slate-700 rounded-lg p-3 h-64 overflow-y-auto">
                {auditLog.length > 0 ? (
                    <ul className="space-y-2 text-sm">
                    {auditLog.map((log, index) => (
                        <li key={index} className="font-mono text-gray-700 dark:text-gray-300">
                        <span className="text-gray-500 dark:text-gray-400">{new Date(log.timestamp).toLocaleString()}:</span> {log.action}
                        </li>
                    ))}
                    </ul>
                ) : (
                    <p className="text-gray-500 dark:text-gray-400 text-center pt-8">No audit logs found.</p>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { GoogleGenAI } from '@google/genai';
import { TestResult, TestStatus } from '../types';
import { Beaker, CheckCircle2, XCircle, Loader } from './icons';

const PuppeteerSelfTest = () => {
  const [testResults, setTestResults] = useState<TestResult[]>([]);
  const [isRunning, setIsRunning] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedScreenshot, setSelectedScreenshot] = useState<string | null>(null);

  const getStatusIcon = (status: TestStatus) => {
    switch (status) {
      case 'running':
        return <Loader className="w-5 h-5 text-blue-500 animate-spin" />;
      case 'passed':
        return <CheckCircle2 className="w-5 h-5 text-green-500" />;
      case 'failed':
        return <XCircle className="w-5 h-5 text-red-500" />;
      case 'pending':
      default:
        return <Beaker className="w-5 h-5 text-gray-400 dark:text-gray-500" />;
    }
  };

  const parseStreamingJson = (text: string): TestResult[] => {
      // This regex is designed to find JSON objects that might be embedded in a streaming text response.
      const jsonRegex = /\{[\s\S]*?\}/g;
      const matches = text.match(jsonRegex);
      if (!matches) return [];

      return matches.map(match => {
          try {
              return JSON.parse(match) as TestResult;
          } catch (e) {
              // Ignore parsing errors for incomplete JSON
              return null;
          }
      }).filter((item): item is TestResult => item !== null);
  };

  const runTests = async () => {
    setIsRunning(true);
    setError(null);
    setTestResults([]);

    const testPrompt = `
      Act as a QA automation engineer. Generate and immediately execute a simulated Puppeteer test suite for a 'Compliance Workflow Dashboard' React application.

      The application has the following features:
      - A dashboard to select different compliance frameworks (e.g., 'Standard Project Refresh', 'HIPAA').
      - Each framework has multiple phases. Users can mark phases as 'in-progress', 'complete', or 'blocked'.
      - A theme switcher for 'light', 'dark', and 'high-contrast' modes.
      - A password-protected Admin Panel with an audit log.
      - Progress is saved in localStorage.

      The critical user journeys to test are:
      1.  **Initial Load**: Verify the dashboard loads with the default framework.
      2.  **Framework Switching**: Switch to the 'HIPAA' framework and verify the phases update.
      3.  **Phase Status Update**: Mark a phase as 'complete' and verify its status icon changes.
      4.  **Progress Bar Update**: Verify the progress bar updates after a phase is completed.
      5.  **Theme Switching**: Switch to 'dark' mode and verify the UI changes.
      6.  **Admin Panel Access**:
          - Fail to log in with an incorrect password.
          - Successfully log in with the correct password (assume default is 'password123' for the test).
      7.  **Directive Copying**: Expand a phase and copy its directive.

      Stream the results back as a sequence of individual JSON objects, one for each test case. Each JSON object must have this exact structure:
      {
        "name": "string (The name of the test case)",
        "status": "'passed' | 'failed'",
        "error": "string | null (The error message if it failed, null otherwise)",
        "screenshot": "string | null (A base64 encoded PNG data URI representing the final UI state. Generate a simple but representative wireframe-style image for each test.)"
      }
      Do not wrap the JSON objects in a list or markdown. Stream them one after another.
    `;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
      const stream = await ai.models.generateContentStream({
          model: 'gemini-2.5-flash',
          contents: testPrompt,
      });

      let accumulatedText = "";
      for await (const chunk of stream) {
          accumulatedText += chunk.text;
          const newResults = parseStreamingJson(accumulatedText);

          if (newResults.length > 0) {
              setTestResults(prevResults => {
                  const updatedResults = [...prevResults];
                  newResults.forEach(newResult => {
                      const existingIndex = updatedResults.findIndex(r => r.name === newResult.name);
                      if (existingIndex > -1) {
                          updatedResults[existingIndex] = newResult;
                      } else {
                          updatedResults.push(newResult);
                      }
                  });
                  return updatedResults;
              });

              // Reset accumulated text after successful parsing to avoid reprocessing
              accumulatedText = ""; 
          }
      }
    } catch (e: any) {
      console.error(e);
      setError(`An error occurred while running the tests: ${e.message}`);
    } finally {
      setIsRunning(false);
    }
  };


  return (
    <>
      <section className="bg-white dark:bg-[#2D241E] rounded-xl shadow-lg p-6 hc-bg hc-border">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
          <div>
            <h2 className="text-xl font-bold text-[#2D241E] dark:text-[#EAE0D5] hc-text-yellow">Puppeteer Self-Test Suite</h2>
            <p className="text-gray-600 dark:text-[#C5A059] hc-text">Run an AI-generated and simulated test suite against the application's critical user journeys.</p>
          </div>
          <button
            onClick={runTests}
            disabled={isRunning}
            className="flex items-center justify-center space-x-2 px-6 py-3 bg-[#C5A059] text-white font-semibold rounded-lg hover:bg-[#B08D4C] transition-colors disabled:bg-[#C5A059]/50 disabled:cursor-not-allowed w-full sm:w-auto"
          >
            {isRunning ? (
              <>
                <Loader className="w-5 h-5 animate-spin" />
                <span>Running Tests...</span>
              </>
            ) : (
              <>
                <Beaker className="w-5 h-5" />
                <span>Generate & Run Tests</span>
              </>
            )}
          </button>
        </div>

        {error && (
            <div className="bg-red-100 border-l-4 border-red-500 text-red-700 p-4 mb-6" role="alert">
                <p className="font-bold">Error</p>
                <p>{error}</p>
            </div>
        )}

        <div className="bg-[#F9F7F2] dark:bg-[#1F1A17]/50 border border-gray-200 dark:border-slate-700 rounded-lg p-4 min-h-[300px] hc-bg hc-border">
          <h3 className="text-lg font-semibold text-[#2D241E] dark:text-[#EAE0D5] mb-4 hc-text">Test Results</h3>
          <ul className="space-y-3">
            {testResults.length === 0 && !isRunning && (
              <li className="text-center py-10 text-gray-500 dark:text-gray-400 hc-text">
                Click "Generate & Run Tests" to begin the self-test process.
              </li>
            )}
            {testResults.map((result, index) => (
              <li key={index} className="p-4 bg-white dark:bg-[#2D241E] rounded-lg shadow-sm border border-gray-200 dark:border-slate-700 hc-bg hc-border">
                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                  <div className="flex items-center space-x-3 flex-1 min-w-0">
                    <div className="flex-shrink-0">{getStatusIcon(result.status)}</div>
                    <p className="font-medium text-[#2D241E] dark:text-[#EAE0D5] truncate hc-text">{result.name}</p>
                  </div>
                  {result.screenshot && (
                    <button 
                      onClick={() => setSelectedScreenshot(result.screenshot || null)}
                      className="text-sm text-[#C5A059] hover:underline dark:text-[#C5A059] font-medium px-3 py-1 bg-[#F9F7F2] dark:bg-[#1F1A17] rounded-md"
                    >
                      View Screenshot
                    </button>
                  )}
                </div>
                {result.status === 'failed' && result.error && (
                  <div className="mt-3 pl-8 text-sm text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/30 p-3 rounded-md">
                    <pre className="whitespace-pre-wrap font-mono"><code>{result.error}</code></pre>
                  </div>
                )}
              </li>
            ))}
             {isRunning && testResults.length === 0 && (
                 <li className="text-center py-10 text-gray-500 dark:text-gray-400 flex items-center justify-center space-x-2">
                    <Loader className="w-5 h-5 animate-spin" />
                    <span>Waiting for test results from the AI...</span>
                </li>
             )}
          </ul>
        </div>
      </section>

      {/* Screenshot Modal */}
      {selectedScreenshot && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4" 
          onClick={() => setSelectedScreenshot(null)}
          aria-modal="true"
          role="dialog"
          aria-labelledby="screenshot-title"
        >
          <div className="bg-white dark:bg-[#2D241E] rounded-lg shadow-2xl w-full max-w-4xl p-4 relative" onClick={(e) => e.stopPropagation()}>
            <h3 id="screenshot-title" className="text-lg font-semibold mb-4 text-[#2D241E] dark:text-[#EAE0D5]">Test Screenshot</h3>
            <button 
              onClick={() => setSelectedScreenshot(null)}
              className="absolute top-2 right-2 p-2 rounded-full text-gray-500 hover:text-gray-800 dark:text-gray-400 dark:hover:text-white text-2xl leading-none"
              aria-label="Close screenshot viewer"
            >
              &times;
            </button>
            <div className="border border-gray-300 dark:border-slate-600 rounded-md overflow-hidden">
                <img src={selectedScreenshot} alt="Test Screenshot" className="w-full h-auto object-contain" />
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default PuppeteerSelfTest;

import React, { useState, useEffect, useMemo } from 'react';
import { Theme, PhaseStatus, PhaseStatuses } from '../types';
import { FRAMEWORKS } from '../constants';
import { CheckCircle2, Circle, Clock, AlertCircle, Copy, Check, ChevronDown, ChevronRight, Lock, Beaker } from './icons';
import { useLocalStorage } from '../hooks';
import AdminPanel from './AdminPanel';
import ThemeSwitcher from './ThemeSwitcher';
import PuppeteerSelfTest from './PuppeteerSelfTest';

const ComplianceWorkflowDashboard = () => {
  const [selectedFramework, setSelectedFramework] = useState('standard');
  const [expandedPhase, setExpandedPhase] = useState<string | null>(null);
  const [phaseStatuses, setPhaseStatuses] = useLocalStorage<PhaseStatuses>('compliance-progress', {});
  const [copiedPhase, setCopiedPhase] = useState<string | null>(null);
  const [copiedItemsPhase, setCopiedItemsPhase] = useState<string | null>(null);
  const [theme, setTheme] = useLocalStorage<Theme>('compliance-theme', 'light');
  const [isAdminPanelOpen, setIsAdminPanelOpen] = useState(false);
  const [activeView, setActiveView] = useState<'dashboard' | 'testing'>('dashboard');

  // Apply theme to the document
  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    root.setAttribute('data-theme', theme);
  }, [theme]);


  const updatePhaseStatus = (phaseId: string, status: PhaseStatus) => {
    setPhaseStatuses(prevStatuses => {
        const newStatuses = { ...prevStatuses };
        if (status === null) {
            delete newStatuses[phaseId];
        } else {
            newStatuses[phaseId] = status;
        }
        return newStatuses;
    });
  };

  const copyToClipboard = async (text: string, phaseId: string) => {
    if (!text) return;
    try {
      await navigator.clipboard.writeText(text);
      setCopiedPhase(phaseId);
      setTimeout(() => setCopiedPhase(null), 2000);
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  const copyItemsToClipboard = async (items: string[], phaseId: string) => {
    if (!items || items.length === 0) return;
    const text = items.map(item => `- ${item}`).join('\n');
    try {
      await navigator.clipboard.writeText(text);
      setCopiedItemsPhase(phaseId);
      setTimeout(() => setCopiedItemsPhase(null), 2000);
    } catch (err) {
      console.error('Failed to copy items:', err);
    }
  };

  const getStatusIcon = (phaseId: string) => {
    const status = phaseStatuses[phaseId];
    switch (status) {
      case 'complete':
        return <CheckCircle2 className="w-5 h-5 text-green-500" />;
      case 'in-progress':
        return <Clock className="w-5 h-5 text-yellow-500" />;
      case 'blocked':
        return <AlertCircle className="w-5 h-5 text-red-500" />;
      default:
        return <Circle className="w-5 h-5 text-gray-400 dark:text-gray-500" />;
    }
  };

  const resetProgress = () => {
    if (window.confirm('Are you sure you want to reset all progress for this framework? This cannot be undone.')) {
        const newStatuses = { ...phaseStatuses };
        FRAMEWORKS[selectedFramework].phases.forEach(phase => {
            delete newStatuses[phase.id];
        });
        setPhaseStatuses(newStatuses);
    }
  };

  const currentFramework = FRAMEWORKS[selectedFramework];

  // Logic to calculate overall progress percentage
  // Automatically updates when phaseStatuses or currentFramework changes
  const progressStats = useMemo(() => {
    const totalPhases = currentFramework.phases.length;
    const completedPhases = currentFramework.phases.filter(p => phaseStatuses[p.id] === 'complete').length;
    const percentage = totalPhases > 0 ? Math.round((completedPhases / totalPhases) * 100) : 0;

    return {
      total: totalPhases,
      completed: completedPhases,
      percentage
    };
  }, [currentFramework, phaseStatuses]);

  const { percentage: progress, completed, total } = progressStats;

  return (
    <>
      <div className="min-h-screen bg-[#F9F7F2] dark:bg-[#1F1A17] p-4 sm:p-6 transition-colors duration-300">
        <div className="max-w-7xl mx-auto">
          {/* Header */}
          <header className="bg-white dark:bg-[#2D241E] border-b-4 border-[#C5A059] rounded-xl shadow-lg p-6 mb-6 hc-bg hc-border">
             <div className="flex justify-between items-start gap-4">
                <div>
                    <h1 className="text-2xl sm:text-3xl font-bold text-[#2D241E] dark:text-[#EAE0D5] hc-text-yellow">Compliance Workflow Dashboard</h1>
                    <p className="text-gray-600 dark:text-[#C5A059] text-sm sm:text-base hc-text">AI Studio Project Refresh & Compliance Implementation Tracker</p>
                </div>
                <div className="flex items-center space-x-2 flex-shrink-0">
                    <ThemeSwitcher theme={theme} setTheme={setTheme} />
                    <button onClick={() => setIsAdminPanelOpen(true)} className="p-2 rounded-full transition-colors duration-200 text-[#2D241E] hover:text-[#C5A059] dark:text-[#EAE0D5] dark:hover:text-[#C5A059] bg-gray-100 dark:bg-slate-700/50 hc-bg hc-border hc-text" aria-label="Open Admin Panel" title="Open Admin Panel">
                        <Lock className="w-5 h-5" />
                    </button>
                </div>
            </div>
          </header>

          {/* View Tabs */}
          <div className="mb-6">
            <div className="border-b border-gray-200 dark:border-slate-700 hc-border">
              <nav className="-mb-px flex space-x-6" aria-label="Tabs">
                <button
                  onClick={() => setActiveView('dashboard')}
                  className={`group inline-flex items-center py-4 px-1 border-b-2 font-medium text-sm transition-colors ${
                    activeView === 'dashboard'
                      ? 'border-[#C5A059] text-[#2D241E] dark:text-[#C5A059] hc-text-yellow hc-border'
                      : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:text-gray-400 dark:hover:text-gray-200 dark:hover:border-slate-600'
                  }`}
                >
                  <CheckCircle2 className="-ml-0.5 mr-2 h-5 w-5" />
                  <span>Dashboard</span>
                </button>
                <button
                  onClick={() => setActiveView('testing')}
                  className={`group inline-flex items-center py-4 px-1 border-b-2 font-medium text-sm transition-colors ${
                    activeView === 'testing'
                      ? 'border-[#C5A059] text-[#2D241E] dark:text-[#C5A059] hc-text-yellow hc-border'
                      : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:text-gray-400 dark:hover:text-gray-200 dark:hover:border-slate-600'
                  }`}
                >
                  <Beaker className="-ml-0.5 mr-2 h-5 w-5" />
                  <span>Puppeteer Self-Test</span>
                </button>
              </nav>
            </div>
          </div>

          {activeView === 'dashboard' ? (
            <>
              {/* Framework Selector */}
              <section className="bg-white dark:bg-[#2D241E] rounded-xl shadow-lg p-6 mb-6 hc-bg hc-border">
                <h2 className="text-lg font-semibold text-[#2D241E] dark:text-[#EAE0D5] mb-4 hc-text-yellow">Select Framework</h2>
                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3">
                  {Object.entries(FRAMEWORKS).map(([key, framework]) => (
                    <button
                      key={key}
                      onClick={() => setSelectedFramework(key)}
                      className={`p-4 rounded-lg border-2 transition-all duration-200 text-left focus:outline-none focus:ring-2 focus:ring-offset-2 dark:focus:ring-offset-[#1F1A17] focus:ring-[#C5A059] ${
                        selectedFramework === key
                          ? `${framework.color} text-white border-transparent shadow-md`
                          : 'bg-white text-gray-700 border-gray-200 hover:border-[#C5A059] hover:bg-gray-50 dark:bg-[#1F1A17] dark:text-[#EAE0D5] dark:border-slate-600 dark:hover:border-[#C5A059] dark:hover:bg-[#3E3228] hc-bg hc-border hc-text'
                      }`}
                    >
                      <div className="font-semibold text-sm">{framework.name}</div>
                      <div className="text-xs mt-1 opacity-90">{framework.phases.length} phases</div>
                    </button>
                  ))}
                </div>
              </section>

              {/* Progress Bar */}
              <section className="bg-white dark:bg-[#2D241E] rounded-xl shadow-lg p-6 mb-6 hc-bg hc-border">
                <div className="flex justify-between items-center mb-3">
                  <h2 className="text-lg font-semibold text-[#2D241E] dark:text-[#EAE0D5] hc-text-yellow">Overall Progress</h2>
                  <button
                    onClick={resetProgress}
                    className="text-sm text-red-600 hover:text-red-800 dark:text-red-400 dark:hover:text-red-300 font-medium transition-colors"
                  >
                    Reset Progress
                  </button>
                </div>
                <div className="w-full bg-gray-200 dark:bg-[#1F1A17] rounded-full h-4 mb-2 overflow-hidden hc-bg hc-border">
                  <div
                    className={`h-4 rounded-full ${currentFramework.color} transition-all duration-500 ease-out`}
                    style={{ width: `${progress}%` }}
                  ></div>
                </div>
                <div className="flex justify-between items-center">
                    <p className="text-sm text-gray-600 dark:text-gray-400 hc-text">{progress}% Complete ({completed}/{total} phases)</p>
                    {progress === 100 && (
                        <span className="text-sm font-bold text-green-600 dark:text-green-400 animate-pulse flex items-center bg-green-50 dark:bg-green-900/30 px-3 py-1 rounded-full">
                            <CheckCircle2 className="w-4 h-4 mr-1" />
                            Framework Completed!
                        </span>
                    )}
                </div>
              </section>

              {/* Phase List */}
              <main className="space-y-4">
                {currentFramework.phases.map((phase) => (
                  <div key={phase.id} className="bg-white dark:bg-[#2D241E] rounded-xl shadow-lg overflow-hidden transition-shadow hover:shadow-xl dark:hover:shadow-[#C5A059]/20 hc-bg hc-border">
                    {/* Phase Header */}
                    <div className="p-6">
                      <div className="flex items-start justify-between">
                        <div className="flex items-start space-x-4 flex-1 min-w-0">
                          <div className="mt-1 flex-shrink-0">
                            {getStatusIcon(phase.id)}
                          </div>
                          <div className="flex-1 min-w-0">
                            <h3 className="text-lg font-semibold text-[#2D241E] dark:text-[#EAE0D5] mb-2 truncate hc-text-yellow">{phase.name}</h3>
                            <div className="flex items-center gap-2 mb-3">
                                <div className="flex flex-wrap gap-2">
                                    {phase.items.map((item, i) => (
                                    <span key={i} className="text-xs bg-gray-100 text-gray-700 px-3 py-1 rounded-full dark:bg-[#3E3228] dark:text-[#EAE0D5] hc-bg hc-border hc-text">
                                        {item}
                                    </span>
                                    ))}
                                </div>
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        copyItemsToClipboard(phase.items, phase.id);
                                    }}
                                    className="p-1.5 rounded-md hover:bg-gray-100 dark:hover:bg-[#3E3228] text-gray-400 hover:text-[#C5A059] transition-colors focus:outline-none focus:ring-2 focus:ring-[#C5A059]"
                                    title="Copy items list"
                                    aria-label="Copy items list"
                                >
                                    {copiedItemsPhase === phase.id ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                                </button>
                            </div>
                          </div>
                        </div>

                        <div className="flex items-center space-x-2 ml-4 flex-shrink-0">
                          {phase.directive && (
                            <button
                              onClick={() => setExpandedPhase(expandedPhase === phase.id ? null : phase.id)}
                              className="p-2 hover:bg-gray-100 dark:hover:bg-[#3E3228] rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-[#C5A059] hc-hover-bg-gray"
                              aria-expanded={expandedPhase === phase.id}
                              aria-controls={`directive-${phase.id}`}
                              aria-label={expandedPhase === phase.id ? "Collapse directive" : "Expand directive"}
                            >
                              {expandedPhase === phase.id ? (
                                <ChevronDown className="w-5 h-5 text-gray-600 dark:text-gray-400 hc-text" />
                              ) : (
                                <ChevronRight className="w-5 h-5 text-gray-600 dark:text-gray-400 hc-text" />
                              )}
                            </button>
                          )}
                        </div>
                      </div>

                      {/* Status Buttons */}
                      <div className="flex flex-wrap gap-2 mt-4">
                        <button onClick={() => updatePhaseStatus(phase.id, 'in-progress')} className={`hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium transition-colors ${phaseStatuses[phase.id] === 'in-progress' ? 'bg-yellow-500 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-[#1F1A17] dark:text-[#EAE0D5] dark:hover:bg-[#3E3228]'}`}>In Progress</button>
                        <button onClick={() => updatePhaseStatus(phase.id, 'complete')} className={`hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium transition-colors ${phaseStatuses[phase.id] === 'complete' ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-[#1F1A17] dark:text-[#EAE0D5] dark:hover:bg-[#3E3228]'}`}>Complete</button>
                        <button onClick={() => updatePhaseStatus(phase.id, 'blocked')} className={`hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium transition-colors ${phaseStatuses[phase.id] === 'blocked' ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-[#1F1A17] dark:text-[#EAE0D5] dark:hover:bg-[#3E3228]'}`}>Blocked</button>
                        {phaseStatuses[phase.id] && (
                          <button onClick={() => updatePhaseStatus(phase.id, null)} className="hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-[#1F1A17] dark:text-[#EAE0D5] dark:hover:bg-[#3E3228]">Clear</button>
                        )}
                      </div>
                    </div>

                    {/* Expandable Directive */}
                    {phase.directive && expandedPhase === phase.id && (
                      <div id={`directive-${phase.id}`} className="border-t border-gray-200 bg-gray-50 p-6 dark:border-slate-700 dark:bg-[#1F1A17]/50 hc-bg hc-border">
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-3 gap-3">
                          <h4 className="font-semibold text-[#2D241E] dark:text-[#EAE0D5] hc-text-yellow">Copy & Paste Directive</h4>
                          <button
                            onClick={() => copyToClipboard(phase.directive || '', phase.id)}
                            className="flex items-center space-x-2 px-4 py-2 bg-[#C5A059] text-white rounded-lg hover:bg-[#B08D4C] transition-colors w-full sm:w-auto justify-center"
                          >
                            {copiedPhase === phase.id ? (
                              <>
                                <Check className="w-4 h-4" />
                                <span>Copied!</span>
                              </>
                            ) : (
                              <>
                                <Copy className="w-4 h-4" />
                                <span>Copy Directive</span>
                              </>
                            )}
                          </button>
                        </div>
                        <pre className="bg-[#2D241E] text-[#EAE0D5] p-4 rounded-lg border border-gray-200 text-sm overflow-x-auto whitespace-pre-wrap font-mono selection:bg-[#C5A059] selection:text-white dark:border-slate-700 hc-bg-code hc-text-code hc-border">
                          {phase.directive}
                        </pre>
                      </div>
                    )}
                  </div>
                ))}
              </main>

              {/* Footer Info */}
              <footer className="mt-8 bg-[#F9F7F2] border border-[#C5A059]/30 rounded-xl p-6 dark:bg-[#2D241E] dark:border-[#C5A059]/30 hc-bg-info">
                <h3 className="font-semibold text-[#2D241E] dark:text-[#C5A059] mb-2 hc-text-info">Usage Instructions</h3>
                <ul className="text-sm text-[#3E3228] dark:text-[#EAE0D5] list-disc list-inside space-y-1 hc-text">
                  <li>Click the arrow icon on a phase to expand and view the full directive.</li>
                  <li>Use "Copy Directive" to copy the phase instructions to your clipboard.</li>
                  <li>Use the copy icon next to the phase items to copy the list of items.</li>
                  <li>Paste the directive into AI Studio and wait for completion confirmation.</li>
                  <li>Mark phases as "In Progress", "Complete", or "Blocked" to track your progress.</li>
                  <li>Your progress is automatically saved and will persist across sessions.</li>
                  <li>Switch between frameworks to manage different compliance implementations.</li>
                </ul>
                <div className="mt-4 pt-4 border-t border-[#C5A059]/30 text-xs text-center text-[#2D241E] dark:text-[#EAE0D5] opacity-75">
                  System Version 3.0 • Project Refresh Baseline
                </div>
              </footer>
            </>
          ) : (
            <PuppeteerSelfTest />
          )}

        </div>
      </div>
      <AdminPanel isOpen={isAdminPanelOpen} onClose={() => setIsAdminPanelOpen(false)} />
    </>
  );
};

export default ComplianceWorkflowDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { useLocalStorage, useSimpleHash } from '../hooks';
import { AuditLogEntry } from '../types';
import { ShieldCheck, Lock } from './icons';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ isOpen, onClose }) => {
  const [passwordHash, setPasswordHash] = useLocalStorage<string | null>('admin-password-hash', null);
  const [auditLog, setAuditLog] = useLocalStorage<AuditLogEntry[]>('admin-audit-log', []);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const hash = useSimpleHash();

  const passwordInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen && !isAuthenticated) {
      setTimeout(() => passwordInputRef.current?.focus(), 100);
    }
  }, [isOpen, isAuthenticated]);

  const addLog = (action: string) => {
    const newLogEntry: AuditLogEntry = {
      timestamp: new Date().toISOString(),
      action,
    };
    // Prepend to keep the log sorted by most recent
    setAuditLog(currentLog => [newLogEntry, ...currentLog]);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!passwordHash) { // First time setup
      if (passwordInput.length < 8) {
        setError('Password must be at least 8 characters long.');
        return;
      }
      const newHash = await hash(passwordInput);
      setPasswordHash(newHash);
      addLog('Admin password set.');
      setIsAuthenticated(true);
      setError('');
      setPasswordInput('');
    } else { // Login
      const inputHash = await hash(passwordInput);
      if (inputHash === passwordHash) {
        addLog('Admin logged in.');
        setIsAuthenticated(true);
        setError('');
        setPasswordInput('');
      } else {
        addLog('Failed login attempt.');
        setError('Incorrect password.');
      }
    }
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (newPassword.length < 8) {
      setError('New password must be at least 8 characters long.');
      return;
    }
    if (newPassword !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }
    const newHash = await hash(newPassword);
    setPasswordHash(newHash);
    addLog('Admin password changed.');
    setNewPassword('');
    setConfirmPassword('');
    alert('Password changed successfully.');
  };

  const handleLogout = () => {
    addLog('Admin logged out.');
    setIsAuthenticated(false);
    onClose();
  };

  const clearLogs = () => {
    if (window.confirm('Are you sure you want to clear all audit logs?')) {
        addLog('Audit logs cleared.');
        setAuditLog([auditLog[0]]); // Keep the "cleared" log entry
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4 backdrop-blur-sm" aria-modal="true" role="dialog" aria-labelledby="admin-panel-title">
      <div className={`hc-bg hc-border bg-white dark:bg-[#2D241E] border dark:border-[#C5A059]/30 rounded-lg shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto p-6 sm:p-8`}>
        <div className="flex justify-between items-center mb-4 border-b border-gray-200 dark:border-[#C5A059]/20 pb-4">
            <h2 id="admin-panel-title" className="text-2xl font-bold text-[#2D241E] dark:text-[#C5A059] hc-text-yellow">Admin Section</h2>
            <button onClick={onClose} className="p-1 rounded-full text-gray-500 hover:text-[#C5A059] dark:text-gray-400 dark:hover:text-[#C5A059] hc-text text-2xl leading-none transition-colors" aria-label="Close admin panel">&times;</button>
        </div>

        {!isAuthenticated ? (
          <form onSubmit={handleLogin}>
            <h3 className="text-lg font-semibold mb-2 text-[#3E3228] dark:text-[#EAE0D5] hc-text">
                {passwordHash ? 'Admin Login' : 'Create Admin Password'}
            </h3>
            <p className="text-sm text-gray-600 dark:text-[#C5A059]/80 mb-4 hc-text">
                {passwordHash ? 'Enter the password to access the admin section.' : 'Create a password to secure the admin section. Minimum 8 characters.'}
            </p>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 dark:text-[#C5A059]/70" />
              <input
                ref={passwordInputRef}
                type="password"
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                placeholder="Enter password"
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-[#C5A059] focus:border-[#C5A059] dark:bg-[#1F1A17] dark:border-[#C5A059]/30 dark:text-[#EAE0D5] dark:placeholder-gray-500"
                aria-label="Admin password"
              />
            </div>
            {error && <p className="text-red-500 dark:text-red-400 text-sm mt-2">{error}</p>}
            <button type="submit" className="mt-4 w-full bg-[#C5A059] text-white font-semibold py-2 px-4 rounded-md hover:bg-[#B08D4C] transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#C5A059] dark:ring-offset-[#2D241E]">
              {passwordHash ? 'Login' : 'Set Password'}
            </button>
          </form>
        ) : (
          <div className="space-y-8">
            <div className="flex justify-between items-center bg-green-50 dark:bg-green-900/20 p-3 rounded-lg border border-green-200 dark:border-green-800">
                <div className="flex items-center space-x-2">
                    <ShieldCheck className="w-6 h-6 text-green-600 dark:text-green-400" />
                    <span className="font-semibold text-green-700 dark:text-green-400">Authenticated</span>
                </div>
                <button onClick={handleLogout} className="text-sm text-red-600 hover:text-red-800 dark:text-red-400 dark:hover:text-red-300 font-medium transition-colors">Logout</button>
            </div>

            <div className="p-4 border border-gray-200 dark:border-[#C5A059]/30 rounded-lg bg-gray-50/50 dark:bg-[#1F1A17]/30">
                <h3 className="text-lg font-semibold mb-2 text-[#3E3228] dark:text-[#EAE0D5] hc-text">Change Password</h3>
                <form onSubmit={handleChangePassword} className="space-y-3">
                    <input type="password" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="New Password" className="w-full p-2 border border-gray-300 rounded-md dark:bg-[#1F1A17] dark:border-[#C5A059]/30 dark:text-[#EAE0D5] focus:border-[#C5A059] focus:ring-[#C5A059]" aria-label="New admin password"/>
                    <input type="password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm New Password" className="w-full p-2 border border-gray-300 rounded-md dark:bg-[#1F1A17] dark:border-[#C5A059]/30 dark:text-[#EAE0D5] focus:border-[#C5A059] focus:ring-[#C5A059]" aria-label="Confirm new admin password"/>
                    {error && <p className="text-red-500 dark:text-red-400 text-sm">{error}</p>}
                    <button type="submit" className="bg-[#C5A059] text-white font-semibold py-2 px-4 rounded-md hover:bg-[#B08D4C] transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#C5A059] dark:ring-offset-[#2D241E]">Update Password</button>
                </form>
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <h3 className="text-lg font-semibold text-[#3E3228] dark:text-[#EAE0D5] hc-text">Audit Log</h3>
                <button onClick={clearLogs} className="text-sm text-red-600 hover:text-red-800 dark:text-red-400 dark:hover:text-red-300 font-medium transition-colors">Clear Logs</button>
              </div>
              <div role="log" className="bg-[#F9F7F2] dark:bg-[#1F1A17] border border-gray-200 dark:border-[#C5A059]/30 rounded-lg p-3 h-64 overflow-y-auto shadow-inner">
                {auditLog.length > 0 ? (
                    <ul className="space-y-2 text-sm">
                    {auditLog.map((log, index) => (
                        <li key={index} className="font-mono text-gray-700 dark:text-[#C5A059]/90 border-b border-gray-100 dark:border-[#C5A059]/10 last:border-0 pb-1">
                        <span className="text-gray-400 dark:text-gray-500 mr-2">[{new Date(log.timestamp).toLocaleString()}]</span>
                        {log.action}
                        </li>
                    ))}
                    </ul>
                ) : (
                    <p className="text-gray-500 dark:text-gray-500 text-center pt-8">No audit logs found.</p>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Theme, PhaseStatus, PhaseStatuses } from '../types';
import { FRAMEWORKS } from '../constants';
import { CheckCircle2, Circle, Clock, AlertCircle, Copy, Check, ChevronDown, ChevronRight, Lock, Beaker } from './icons';
import { useLocalStorage } from '../hooks';
import AdminPanel from './AdminPanel';
import ThemeSwitcher from './ThemeSwitcher';
import PuppeteerSelfTest from './PuppeteerSelfTest';

const ComplianceWorkflowDashboard = () => {
  const [selectedFramework, setSelectedFramework] = useState('standard');
  const [expandedPhase, setExpandedPhase] = useState<string | null>(null);
  const [phaseStatuses, setPhaseStatuses] = useLocalStorage<PhaseStatuses>('compliance-progress', {});
  const [copiedPhase, setCopiedPhase] = useState<string | null>(null);
  const [copiedItemsPhase, setCopiedItemsPhase] = useState<string | null>(null);
  const [theme, setTheme] = useLocalStorage<Theme>('compliance-theme', 'light');
  const [isAdminPanelOpen, setIsAdminPanelOpen] = useState(false);
  const [activeView, setActiveView] = useState<'dashboard' | 'testing'>('dashboard');

  const dashboardPanelRef = useRef<HTMLDivElement>(null);
  const testingPanelRef = useRef<HTMLDivElement>(null);

  // Apply theme to the document
  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    root.setAttribute('data-theme', theme);
  }, [theme]);

  // Manage focus between views
  useEffect(() => {
    if (activeView === 'dashboard') {
      dashboardPanelRef.current?.focus();
    } else {
      testingPanelRef.current?.focus();
    }
  }, [activeView]);


  const updatePhaseStatus = (phaseId: string, status: PhaseStatus) => {
    setPhaseStatuses(prevStatuses => {
        const newStatuses = { ...prevStatuses };
        if (status === null) {
            delete newStatuses[phaseId];
        } else {
            newStatuses[phaseId] = status;
        }
        return newStatuses;
    });
  };

  const copyToClipboard = async (text: string, phaseId: string) => {
    if (!text) return;
    try {
      await navigator.clipboard.writeText(text);
      setCopiedPhase(phaseId);
      setTimeout(() => setCopiedPhase(null), 2000);
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  const copyItemsToClipboard = async (items: string[], phaseId: string) => {
    if (!items || items.length === 0) return;
    const text = items.map(item => `- ${item}`).join('\n');
    try {
      await navigator.clipboard.writeText(text);
      setCopiedItemsPhase(phaseId);
      setTimeout(() => setCopiedItemsPhase(null), 2000);
    } catch (err) {
      console.error('Failed to copy items:', err);
    }
  };

  const getStatusIcon = (phaseId: string) => {
    const status = phaseStatuses[phaseId];
    switch (status) {
      case 'complete':
        return <CheckCircle2 className="w-5 h-5 text-green-500" />;
      case 'in-progress':
        return <Clock className="w-5 h-5 text-yellow-500" />;
      case 'blocked':
        return <AlertCircle className="w-5 h-5 text-red-500" />;
      default:
        return <Circle className="w-5 h-5 text-gray-400 dark:text-gray-500" />;
    }
  };

  const resetProgress = () => {
    if (window.confirm('Are you sure you want to reset all progress for this framework? This cannot be undone.')) {
        const newStatuses = { ...phaseStatuses };
        FRAMEWORKS[selectedFramework].phases.forEach(phase => {
            delete newStatuses[phase.id];
        });
        setPhaseStatuses(newStatuses);
    }
  };

  const currentFramework = FRAMEWORKS[selectedFramework];

  // Logic to calculate overall progress percentage
  // Automatically updates when phaseStatuses or currentFramework changes
  const progressStats = useMemo(() => {
    const totalPhases = currentFramework.phases.length;
    const completedPhases = currentFramework.phases.filter(p => phaseStatuses[p.id] === 'complete').length;
    const percentage = totalPhases > 0 ? Math.round((completedPhases / totalPhases) * 100) : 0;

    return {
      total: totalPhases,
      completed: completedPhases,
      percentage
    };
  }, [currentFramework, phaseStatuses]);

  const { percentage: progress, completed, total } = progressStats;

  return (
    <>
      <div className="min-h-screen bg-[#F9F7F2] dark:bg-[#1F1A17] p-4 sm:p-6 transition-colors duration-300">
        <div className="max-w-7xl mx-auto">
          {/* Header */}
          <header className="bg-white dark:bg-[#2D241E] border-b-4 border-[#C5A059] rounded-xl shadow-lg p-6 mb-6 hc-bg hc-border">
