                          aria-label={`Mark ${phase.name} as Blocked`}
                          className={`hc-btn px-3 py-1.5 sm:px-4 sm:py-2 rounded-lg text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-red-500 ${phaseStatuses[phase.id] === 'blocked' ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-[#1F1A17] dark:text-[#EAE0D5] dark:hover:bg-[#3E3228]'}`}
                        >
